import{_ as l,L as i,c as u,o as c,aq as d,O as o,z as s,b as e,x as a}from"./chunks/framework.jeRwkH3J.js";const v=JSON.parse('{"title":"General","description":"Frequently Asked Questions","frontmatter":{"title":"General","description":"Frequently Asked Questions","footer":false},"headers":[],"relativePath":"manuals/faq/general/index.md","filePath":"manuals/faq/general/index.md","lastUpdated":1776356367000,"breadcrumbs":[{"text":"User manual","link":"/manuals/guides/getting-started/"},{"text":"Frequently Asked Questions","items":[{"text":"General","link":"/manuals/faq/general/"},{"text":"Feed","link":"/manuals/faq/feed/"},{"text":"Explore","collapsed":true,"items":[{"text":"Sources","link":"/manuals/faq/explore/sources/"},{"text":"Downloads","link":"/manuals/faq/explore/downloads/"}]},{"text":"Reader","link":"/manuals/faq/reader/"},{"text":"Settings","link":"/manuals/faq/settings/"},{"text":"Miscellaneous","link":"/manuals/faq/miscellaneous/"}]},{"text":"General","link":"/manuals/faq/general/"}]}'),p={name:"manuals/faq/general/index.md"};function h(g,t,m,f,b,k){const n=i("PluginTabsTab"),r=i("PluginTabs");return c(),u("div",null,[t[2]||(t[2]=d('<h1 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h1><p>Frequently Asked Questions</p><h2 id="what-is-usagi" tabindex="-1">What is Usagi? <a class="header-anchor" href="#what-is-usagi" aria-label="Permalink to &quot;What is Usagi?&quot;">​</a></h2><p>Usagi is an open-source <strong>Android</strong> app that lets you read any from your device - faster and easier than ever.</p><div class="tip custom-block"><p class="custom-block-title">Disclaimer</p><p>Usagi is not hosting any content, we are not affilated with or responsible for any content.</p></div><h2 id="where-do-i-post-app-issues" tabindex="-1">Where do i post app issues, bugs or feature requests? <a class="header-anchor" href="#where-do-i-post-app-issues" aria-label="Permalink to &quot;Where do i post app issues, bugs or feature requests?&quot;">​</a></h2><p>To post app issues, bugs, and feature requests please open a ticket on GitHub by following the link <a href="https://github.com/UsagiApp/Usagi/issues/new/choose" target="_blank" rel="noreferrer">here</a></p><h2 id="why-isnt-usagi-on-the-google" tabindex="-1">Why isn&#39;t Usagi on the Google Play Store? <a class="header-anchor" href="#why-isnt-usagi-on-the-google" aria-label="Permalink to &quot;Why isn&#39;t Usagi on the Google Play Store?&quot;">​</a></h2><p><strong>Usagi</strong> won&#39;t be on the <strong>Google Play Store</strong>. <strong>Google</strong> might take down the app due to certain content, which the developers wishes to avoid.</p><p>To report <strong>Usagi</strong> copycats on the <strong>Google Play Store</strong>, fill out <a href="https://support.google.com/googleplay/android-developer/contact/takedown" target="_blank" rel="noreferrer">this form</a> following the steps below.</p><details class="details custom-block"><summary>Steps to report Usagi copycats</summary><ol><li><p>Go to the page -&gt; three dots menu -&gt; Flag as inappropriate -&gt; Other objection.</p></li><li><p>After choosing &quot;Other objection&quot;, you may choose to put down any or all of the following:</p><p>The app infringes on the Google Play Developer Policy by</p><p>Encouraging Infringement of Copyright</p><blockquote><p>We don’t allow apps that induce or encourage copyright infringement. Before you publish your app, look for ways your app may be encouraging copyright infringement and get legal advice if necessary.</p></blockquote><p>Trademark Infringement</p><blockquote><p>We don’t allow apps that infringe on others’ trademarks. A trademark is a word, symbol, or combination that identifies the source of a good or service. Once acquired, a trademark gives the owner exclusive rights to the trademark usage with respect to certain goods or services.</p><p>Trademark infringement is an improper or unauthorized use of an identical or similar trademark in a way that is likely to cause confusion as to the source of that product. If your app uses another party’s trademarks in a way that is likely to cause confusion, your app may be suspended.</p></blockquote><p>Misleading Claims, e.g. &quot;MangaTop - Best Manga Reader&quot;</p><blockquote><p>We don’t allow apps that contain false or misleading information or claims, including in the description, title, icon, and screenshots. Here are some examples of common violations: Apps that misrepresent or do not accurately and clearly describe their functionality:</p><ul><li>Developer or app names that misrepresent their current status or performance on Play. (E.g. “Editor’s Choice,” “Number 1 App,” “Top Paid”)...</li><li>Apps that are improperly categorized.</li></ul></blockquote></li></ol></details><h2 id="is-usagi-available-for-iosipados" tabindex="-1">Is Usagi available for iOS/iPadOS? <a class="header-anchor" href="#is-usagi-available-for-iosipados" aria-label="Permalink to &quot;Is Usagi available for iOS/iPadOS?&quot;">​</a></h2><p>There is no iOS or iPadOS version and neither are there plans for one. Porting is difficult due to the separate codebases of iOS and Android apps.</p><p>Any app proclaiming to be &quot;<strong>Usagi for iOS</strong>&quot; is not by us and should be treated as a scam.</p><h2 id="can-i-read-light-novels" tabindex="-1">Can I read light novels? <a class="header-anchor" href="#can-i-read-light-novels" aria-label="Permalink to &quot;Can I read light novels?&quot;">​</a></h2><p><strong>Usagi</strong> can&#39;t read light novels; it&#39;s an image parser, not a text parser.</p><h2 id="can-i-stream-anime" tabindex="-1">Can I stream anime? <a class="header-anchor" href="#can-i-stream-anime" aria-label="Permalink to &quot;Can I stream anime?&quot;">​</a></h2><p><strong>Usagi</strong> isn&#39;t designed for anime streaming.</p><p>Projects using the <strong>Usagi</strong> name for anime streaming aren&#39;t affiliated with the main project.</p><h2 id="can-i-use-usagi-on-desktop" tabindex="-1">Can I use Usagi on desktop? <a class="header-anchor" href="#can-i-use-usagi-on-desktop" aria-label="Permalink to &quot;Can I use Usagi on desktop?&quot;">​</a></h2><p>No, you can&#39;t.</p><h2 id="can-usagi-sync-across-devices" tabindex="-1">Can Usagi sync across devices? <a class="header-anchor" href="#can-usagi-sync-across-devices" aria-label="Permalink to &quot;Can Usagi sync across devices?&quot;">​</a></h2><p>Yes, the application supports synchronization between devices.</p><p>Learn how to create a Usagi Sync account <a href="/manuals/guides/synchronization/">here</a></p><h2 id="what-do-i-do-if-i-have-to" tabindex="-1">What do I do if I have to switch to a new phone? <a class="header-anchor" href="#what-do-i-do-if-i-have-to" aria-label="Permalink to &quot;What do I do if I have to switch to a new phone?&quot;">​</a></h2><p>Please follow these steps:</p><ol><li>Backup your entire favourites and history from your old device and transfer it to your new phone.</li><li>Restore the backup.</li></ol><div class="tip custom-block"><p class="custom-block-title">Note</p><p>More information about backup and restore is listed <a href="/manuals/guides/backups/">here</a>.</p></div><h2 id="can-i-restore-my-tachiyomimihon" tabindex="-1">Can I restore my Tachiyomi/Mihon backup to Usagi? <a class="header-anchor" href="#can-i-restore-my-tachiyomimihon" aria-label="Permalink to &quot;Can I restore my Tachiyomi/Mihon backup to Usagi?&quot;">​</a></h2><p>No, you can&#39;t. This is due to the difficulty in supporting and adapting the <code>.proto.gz</code> or <code>.tachibk</code> format that <strong>Tachiyomi/Mihon</strong> uses. Also <strong>Usagi</strong> and <strong>Tachiyomi</strong> and its forks have different data structures that they use. For <strong>Neko for MangaDex</strong> users, we recommend to use <a href="https://github.com/PhantomShift/nekotatsu" target="_blank" rel="noreferrer">Nekotatsu</a> if you&#39;re on the desktop or <a href="https://github.com/PhantomShift/nekotatsu-mobile" target="_blank" rel="noreferrer">Nekotatsu Mobile</a> for android devices.</p>',30)),o(r,null,{default:s(()=>[o(n,{label:"Nekotatsu"},{default:s(()=>[...t[0]||(t[0]=[e("div",{class:"tip custom-block"},[e("p",{class:"custom-block-title"},"How to use"),e("p",null,"The instructions are based from the project's README.")],-1),e("ol",null,[e("li",null,[a("It is recommended to run the update command first to fetch some necessary files. "),e("code",null,"$ nekotatsu update")]),e("li",null,[a("Then, you can run the conversion command like so: "),e("code",null,"$ nekotatsu convert (neko.tachibk)")])],-1)])]),_:1}),o(n,{label:"Nekotatsu Mobile"},{default:s(()=>[...t[1]||(t[1]=[e("ol",null,[e("li",null,[a("Tap the ⚙️ icon on the top left and tap "),e("code",null,"Download"),a(".")]),e("li",null,[a("Next, you'll need to tap "),e("code",null,"Download"),a(" button on the right for each item (Tachiyomi Sources, Usagi Plugins, Fixer Script) and make sure they have a green checkmark on the left.")]),e("li",null,[a("Tap the ⚙️ icon again on the top left and tap "),e("code",null,"Convert"),a(".")]),e("li",null,[a("To get started, tap the "),e("code",null,"Pick Backup"),a(" button and pick the "),e("code",null,".tachibk"),a(" file you'll want to convert. Next, tap the "),e("code",null,"Pick Save Path"),a(" button and select the path you'll want to save your converted backup onto.")]),e("li",null,[a("Finally, tap the "),e("code",null,"Convert"),a(" button. If it says "),e("code",null,"Conversion completed!"),a(", that means the file is converted successfully.")])],-1)])]),_:1})]),_:1})])}const q=l(p,[["render",h]]);export{v as __pageData,q as default};
